I fixed the issue by using the following snippet

```typescript
import { FastifyReply } from 'fastify';
import ExcelJS from 'exceljs';
import { PassThrough } from 'node:stream';

interface ExportHandler {
  writeHeader(): Promise<void>;
  writeRow(row: any[]): Promise<void>;
  finalize(): Promise<void>;
}

class StreamingXLSXHandler implements ExportHandler {
  private workbook: ExcelJS.stream.xlsx.WorkbookWriter;
  private worksheet: ExcelJS.Worksheet;
  private passThrough: PassThrough;
  private headerWritten = false;

  constructor(
    private reply: FastifyReply,
    private headerRow: string[]
  ) {
    this.passThrough = new PassThrough({
      highWaterMark: 1024 * 1024,
      objectMode: false,
    });

    this.workbook = new ExcelJS.stream.xlsx.WorkbookWriter({
      stream: this.passThrough,
      useSharedStrings: false,
      useStyles: false,
      zip: {
        zlib: { level: 1 },
      },
    });
    this.worksheet = this.workbook.addWorksheet('Test');

    reply.send(this.passThrough);

    this.passThrough.on('error', (error) => {
      console.log('XLSX stream error', error);
    });
  }

  async writeHeader(): Promise<void> {
    if (!this.headerWritten) {
      const headerRow = this.worksheet.addRow(this.headerRow);
      headerRow.commit();
      this.headerWritten = true;
      console.log('XLSX header written manually');
    }
  }

  async writeRow(row: any[]): Promise<void> {
    const sanitizedRow = row.map((cell) => {
      if (cell === null || cell === undefined) {
        return '';
      }
      const cellValue = String(cell);
      return cellValue.length > 32767 ? cellValue.substring(0, 32767) : cellValue;
    });

    const excelRow = this.worksheet.addRow(sanitizedRow);
    excelRow.commit();
  }

  async finalize(): Promise<void> {
    console.log('Finalizing XLSX export');
    this.worksheet.commit();
    await this.workbook.commit();
  }
}
```
